    while (*p != '\n' && *p != '\r') {
        p++;
    }

    protocol_trim_copy(p, input->buffer, sizeof(input->buffer));

    if (strlen(input->buffer) == 0U) {
        return PROTOCOL_PARSE_IGNORED;
    }

    for (i = 0U; i < strlen(input->buffer); i++) {
        if (!isspace((unsigned char) input->buffer[i])) {
            break;
        }
    }

    size_t line_length = strlen(input->buffer);
    protocol_trim_copy(input->buffer, input->buffer + line_length - 1U, sizeof(input->buffer));

